mapper.select:
SELECT warehouse_id, warehouse_code, warehouse_name, location, type, is_active FROM WAREHOUSE
AND (warehouse_name LIKE CONCAT('%', #{keyword}, '%') OR warehouse_code LIKE CONCAT('%', #{keyword}, '%'))
AND type = #{type}
AND is_active = #{isActive}
ORDER BY warehouse_id ASC

